[RUN_CMD]
cat > test_logic.py <<'EOF'
def process_integer(value: int) -> int:
    """Return the integer if valid, else raise TypeError."""
    if not isinstance(value, int):
        raise TypeError(f"Expected int, got {type(value).__name__}")
    return value


def test_string_call():
    """Test calling process_integer with a string, expecting TypeError."""
    try:
        process_integer("not an int")
    except TypeError as e:
        print(f"Caught expected exception: {e}")
    else:
        print("Error: No exception raised for string input")


if __name__ == "__main__":
    # Example usage
    print(process_integer(42))
    test_string_call()
EOF

